<script>
(function(){
"use strict";

/* ============================================================
   PROCEDURAL TEXTURE GENERATION
   ============================================================ */

function createFrontFaceTexture(size){
  const c = document.createElement('canvas');
  c.width = c.height = size;
  const ctx = c.getContext('2d');
  const cx = size/2, cy = size/2, r = size/2 - 4;

  // Base gold gradient
  const grad = ctx.createRadialGradient(cx, cy, r*0.1, cx, cy, r);
  grad.addColorStop(0, '#f5e6a3');
  grad.addColorStop(0.5, '#d4a843');
  grad.addColorStop(1, '#a07828');
  ctx.fillStyle = grad;
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI*2);
  ctx.fill();

  // Inner ring
  ctx.strokeStyle = '#c8943e';
  ctx.lineWidth = 3;
  ctx.beginPath();
  ctx.arc(cx, cy, r*0.85, 0, Math.PI*2);
  ctx.stroke();

  // Outer ring
  ctx.strokeStyle = '#b8862d';
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.arc(cx, cy, r*0.95, 0, Math.PI*2);
  ctx.stroke();

  // Star emblem
  const starR = r * 0.45;
  ctx.fillStyle = '#f0d078';
  ctx.shadowColor = 'rgba(0,0,0,0.5)';
  ctx.shadowBlur = 4;
  ctx.shadowOffsetX = 2;
  ctx.shadowOffsetY = 2;
  drawStar(ctx, cx, cy, 5, starR, starR*0.45);
  ctx.shadowBlur = 0;

  // WastedToken text arc top
  ctx.save();
  ctx.font = `bold ${size*0.07}px 'Segoe UI', sans-serif`;
  ctx.fillStyle = '#8a6420';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.shadowColor = 'rgba(255,255,255,0.3)';
  ctx.shadowBlur = 1;
  ctx.shadowOffsetX = 1;
  ctx.shadowOffsetY = 1;
  ctx.fillText('WASTEDTOKEN', cx, cy - r*0.55);
  ctx.restore();

  // MINT text arc bottom
  ctx.save();
  ctx.font = `bold ${size*0.06}px 'Segoe UI', sans-serif`;
  ctx.fillStyle = '#8a6420';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText('MINT', cx, cy + r*0.55);
  ctx.restore();

  // Small dots around the ring
  ctx.fillStyle = '#c8943e';
  for(let i=0;i<24;i++){
    const a = (i/24)*Math.PI*2;
    const dx = cx + Math.cos(a)*r*0.72;
    const dy = cy + Math.sin(a)*r*0.72;
    ctx.beginPath();
    ctx.arc(dx, dy, 2, 0, Math.PI*2);
    ctx.fill();
  }

  return c;
}

function drawStar(ctx, cx, cy, spikes, outerR, innerR){
  let rot = Math.PI/2*3;
  const step = Math.PI/spikes;
  ctx.beginPath();
  ctx.moveTo(cx, cy - outerR);
  for(let i=0;i<spikes;i++){
    ctx.lineTo(cx + Math.cos(rot)*outerR, cy + Math.sin(rot)*outerR);
    rot += step;
    ctx.lineTo(cx + Math.cos(rot)*innerR, cy + Math.sin(rot)*innerR);
    rot += step;
  }
  ctx.lineTo(cx, cy - outerR);
  ctx.closePath();
  ctx.fill();
}

function createBackFaceTexture(size){
  const c = document.createElement('canvas');
  c.width = c.height = size;
  const ctx = c.getContext('2d');
  const cx = size/2, cy = size/2, r = size/2 - 4;

  // Base silver gradient
  const grad = ctx.createRadialGradient(cx, cy, r*0.1, cx, cy, r);
  grad.addColorStop(0, '#f0f0f5');
  grad.addColorStop(0.5, '#c8c8d0');
  grad.addColorStop(1, '#9090a0');
  ctx.fillStyle = grad;
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI*2);
  ctx.fill();

  // Inner ring
  ctx.strokeStyle = '#a0a0b0';
  ctx.lineWidth = 3;
  ctx.beginPath();
  ctx.arc(cx, cy, r*0.85, 0, Math.PI*2);
  ctx.stroke();

  // Outer ring
  ctx.strokeStyle = '#b0b0c0';
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.arc(cx, cy, r*0.95, 0, Math.PI*2);
  ctx.stroke();

  // Denomination
  ctx.font = `bold ${size*0.14}px 'Segoe UI', sans-serif`;
  ctx.fillStyle = '#505060';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.shadowColor = 'rgba(255,255,255,0.4)';
  ctx.shadowBlur = 2;
  ctx.shadowOffsetX = 1;
  ctx.shadowOffsetY = 1;
  ctx.fillText('10,000', cx, cy - size*0.06);

  ctx.font = `bold ${size*0.07}px 'Segoe UI', sans-serif`;
  ctx.fillStyle = '#606070';
  ctx.fillText('TOKENS', cx, cy + size*0.08);

  // Small decorative elements
  ctx.fillStyle = '#a0a0b0';
  for(let i=0;i<24;i++){
    const a = (i/24)*Math.PI*2;
    const dx = cx + Math.cos(a)*r*0.72;
    const dy = cy + Math.sin(a)*r*0.72;
    ctx.beginPath();
    ctx.arc(dx, dy, 2, 0, Math.PI*2);
    ctx.fill();
  }

  return c;
}

function createSideTexture(size, ridges){
  const c = document.createElement('canvas');
  c.width = size;
  c.height = ridges;
  const ctx = c.getContext('2d');

  // Base metallic gradient
  const grad = ctx.createLinearGradient(0, 0, size, 0);
  grad.addColorStop(0, '#a07828');
  grad.addColorStop(0.3, '#d4a843');
  grad.addColorStop(0.5, '#f0d078');
  grad.addColorStop(0.7, '#d4a843');
  grad.addColorStop(1, '#a07828');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, size, ridges);

  // Reeded ridges
  const ridgeW = 2;
  const gapW = 4;
  for(let x = 0; x < size; x += ridgeW + gapW){
    // Highlight on ridge
    const rg = ctx.createLinearGradient(x, 0, x + ridgeW, 0);
    rg.addColorStop(0, 'rgba(255,255,255,0.3)');
    rg.addColorStop(0.5, 'rgba(255,255,255,0.6)');
    rg.addColorStop(1, 'rgba(0,0,0,0.1)');
    ctx.fillStyle = rg;
    ctx.fillRect(x, 0, ridgeW, ridges);

    // Shadow between ridges
    ctx.fillStyle = 'rgba(0,0,0,0.15)';
    ctx.fillRect(x + ridgeW, 0, gapW, ridges);
  }

  return c;
}

/* ============================================================
   WEBGL COIN RENDERER
   ============================================================ */

function initWebGL(canvas){
  const gl = canvas.getContext('webgl', {antialias:true, alpha:false});
  if(!gl){
    // Fallback: draw a static coin
    const ctx = canvas.getContext('2d');
    const w = canvas.width, h = canvas.height;
    const cx = w/2, cy = h/2, r = Math.min(w,h)*0.38;
    const grad = ctx.createRadialGradient(cx-r*0.3, cy-r*0.3, r*0.1, cx, cy, r);
    grad.addColorStop(0, '#f5e6a3');
    grad.addColorStop(0.5, '#d4a843');
    grad.addColorStop(1, '#8a6420');
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(cx, cy, r, 0, Math.PI*2);
    ctx.fill();
    return null;
  }
  return gl;
}

function compileShader(gl, type, src){
  const s = gl.createShader(type);
  gl.shaderSource(s, src);
  gl.compileShader(s);
  if(!gl.getShaderParameter(s, gl.COMPILE_STATUS)){
    console.error(gl.getShaderInfoLog(s));
    return null;
  }
  return s;
}

function createProgram(gl, vs, fs){
  const p = gl.createProgram();
  gl.attachShader(p, vs);
  gl.attachShader(p, fs);
  gl.linkProgram(p);
  if(!gl.getProgramParameter(p, gl.LINK_STATUS)){
    console.error(gl.getProgramInfoLog(p));
    return null;
  }
  return p;
}

function createTextureFromCanvas(gl, canvas){
  const tex = gl.createTexture();
  gl.bindTexture(gl.TEXTURE_2D, tex);
  gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, canvas);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
  return tex;
}

function buildCoinGeometry(gl, segments, rings){
  // Build cylinder: top face, bottom face, side face
  const positions = [];
  const normals = [];
  const uvs = [];
  const indices = [];

  const topY = 0.15;
  const botY = -0.15;
  const radius = 0.85;

  // Top face (front) - triangles fan from center
  const topCenterIdx = positions.length / 3;
  positions.push(0, topY, 0);
  normals.push(0, 1, 0);
  uvs.push(0.5, 0.5);

  for(let i = 0; i <= segments; i++){
    const a = (i / segments) * Math.PI * 2;
    const x = Math.cos(a) * radius;
    const z = Math.sin(a) * radius;
    positions.push(x, topY, z);
    normals.push(0, 1, 0);
    uvs.push(0.5 + Math.cos(a)*0.5, 0.5 + Math.sin(a)*0.5);
  }

  for(let i = 0; i < segments; i++){
    indices.push(topCenterIdx, topCenterIdx + i + 1, topCenterIdx + i + 2);
  }

  // Bottom face (back) - triangles fan from center
  const botCenterIdx = positions.length / 3;
  positions.push(0, botY, 0);
  normals.push(0, -1, 0);
  uvs.push(0.5, 0.5);

  for(let i = 0; i <= segments; i++){
    const a = (i / segments) * Math.PI * 2;
    const x = Math.cos(a) * radius;
    const z = Math.sin(a) * radius;
    positions.push(x, botY, z);
    normals.push(0, -1, 0);
    uvs.push(0.5 + Math.cos(a)*0.5, 0.5 + Math.sin(a)*0.5);
  }

  for(let i = 0; i < segments; i++){
    indices.push(botCenterIdx, botCenterIdx + i + 2, botCenterIdx + i + 1);
  }

  // Side face
  const sideStartIdx = positions.length / 3;
  const sideRings = 1;
  for(let j = 0; j <= sideRings; j++){
    const y = botY + (topY - botY) * (j / sideRings);
    for(let i = 0; i <= segments; i++){
      const a = (i / segments) * Math.PI * 2;
      const x = Math.cos(a) * radius;
      const z = Math.sin(a) * radius;
      positions.push(x, y, z);
      // Normal points outward
      const nx = Math.cos(a);
      const nz = Math.sin(a);
      const len = Math.sqrt(nx*nx + nz*nz);
      normals.push(nx/len, 0, nz/len);
      uvs.push(i / segments, j);
    }
  }

  for(let j = 0; j < sideRings; j++){
    for(let i = 0; i < segments; i++){
      const a = sideStartIdx + j * (segments + 1) + i;
      const b = a + segments + 1;
      const c = a + 1;
      const d = b + 1;
      indices.push(a, b, c);
      indices.push(c, b, d);
    }
  }

  const posBuf = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, posBuf);
  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(positions), gl.STATIC_DRAW);

  const normBuf = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, normBuf);
  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(normals), gl.STATIC_DRAW);

  const uvBuf = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, uvBuf);
  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(uvs), gl.STATIC_DRAW);

  const idxBuf = gl.createBuffer();
  gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, idxBuf);
  gl.bufferData(gl.ELEMENT_ARRAY_BUFFER, new Uint16Array(indices), gl.STATIC_DRAW);

  return {
    posBuf, normBuf, uvBuf, idxBuf,
    count: indices.length,
    topCenterIdx,
    sideStartIdx,
    segments: segments + 1,
    sideRings: sideRings + 1
  };
}

function renderCoin(gl, canvas, time, frontTex, backTex, sideTex){
  const w = canvas.width;
  const h = canvas.height;
  gl.viewport(0, 0, w, h);

  // Clear with subtle gradient background
  gl.clearColor(0.04, 0.04, 0.06, 1.0);
  gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
  gl.enable(gl.DEPTH_TEST);
  gl.enable(gl.CULL_FACE);
  gl.cullFace(gl.BACK);

  // Compute rotation: vertical axis rotation + horizontal flip
  const t = time % 1;
  const vertAngle = t * Math.PI * 4;  // 2 full rotations
  const horizAngle = Math.sin(t * Math.PI * 2) * Math.PI * 0.45; // flip back and forth

  // Build model-view-projection
  const aspect = w / h;
  const fov = Math.PI / 3;
  const f = 1.0 / Math.tan(fov / 2);

  // Camera position
  const camDist = 3.2;
  const camY = 0.3;

  // View matrix (camera looking at origin from above)
  const view = [
    1, 0, 0, 0,
    0, camDist, 0, 0,
    0, 0, 1, 0,
    0, 0, -camDist, 1
  ];

  // Projection matrix
  const proj = [
    f / aspect, 0, 0, 0,
    0, f, 0, 0,
    0, 0, (0.1 + 10) / (0.1 - 10), -1,
    0, 0, (2 * 0.1 * 10) / (0.1 - 10), 0
  ];

  // Model matrix: rotate around Y (vertical), then X (horizontal flip)
  const cosV = Math.cos(vertAngle), sinV = Math.sin(vertAngle);
  const cosH = Math.cos(horizAngle), sinH = Math.sin(horizAngle);

  // Rotation: first horizontal flip (X axis), then vertical spin (Y axis)
  const model = [
    cosV, sinV * sinH, cosV * sinH, 0,
    0, cosH, -sinH, 0,
    -sinV, cosV * sinH, cosV * cosH, 0,
    0, 0, 0, 1
  ];

  // MVP
  const mvp = mulMat4(proj, mulMat4(view, model));

  // Light direction (fixed in world space, creates moving highlight)
  const lightDir = normalize3([0.5, 0.8, 1.0]);
  const eyePos = [0, camDist, 0];

  // Draw
  gl.useProgram(prog);

  // Set uniforms
  gl.uniformMatrix4fv(uMVP, false, mvp);
  gl.uniformMatrix4fv(uModel, false, model);
  gl.uniform3fv(uLightDir, lightDir);
  gl.uniform3fv(uEyePos, eyePos);
  gl.uniform1f(uTime, time);
  gl.uniform1f(uMetalness, 0.95);
  gl.uniform1f(uRoughness, 0.15);

  // Bind textures
  gl.activeTexture(gl.TEXTURE0);
  gl.bindTexture(gl.TEXTURE_2D, frontTex);
  gl.uniform1i(uTexFront, 0);

  gl.activeTexture(gl.TEXTURE1);
  gl.bindTexture(gl.TEXTURE_2D, backTex);
  gl.uniform1i(uTexBack, 1);

  gl.activeTexture(gl.TEXTURE2);
  gl.bindTexture(gl.TEXTURE_2D, sideTex);
  gl.uniform1i(uTexSide, 2);

  // Bind geometry
  gl.bindBuffer(gl.ARRAY_BUFFER, geo.posBuf);
  gl.enableVertexAttribArray(aPos);
  gl.vertexAttribPointer(aPos, 3, gl.FLOAT, false, 0, 0);

  gl.bindBuffer(gl.ARRAY_BUFFER, geo.normBuf);
  gl.enableVertexAttribArray(aNorm);
  gl.vertexAttribPointer(aNorm, 3, gl.FLOAT, false, 0, 0);

  gl.bindBuffer(gl.ARRAY_BUFFER, geo.uvBuf);
  gl.enableVertexAttribArray(aUV);
  gl.vertexAttribPointer(aUV, 2, gl.FLOAT, false, 0, 0);

  // Draw top face (front)
  gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, geo.idxBuf);
  gl.drawElements(gl.TRIANGLES, geo.segments * 2, gl.UNSIGNED_SHORT, geo.topCenterIdx * 2);

  // Draw bottom face (back)
  gl.drawElements(gl.TRIANGLES, geo.segments * 2, gl.UNSIGNED_SHORT, geo.topCenterIdx * 2 + geo.segments * 2);

  // Draw side face
  const sideIdx = geo.topCenterIdx * 2 + geo.segments * 2 + geo.segments * 2;
  const sideCount = (geo.segments - 1) * geo.sideRings * 6;
  gl.drawElements(gl.TRIANGLES, sideCount, gl.UNSIGNED_SHORT, sideIdx);
}

function mulMat4(a, b){
  const r = new Float32Array(16);
  for(let i=0;i<4;i++) for(let j=0;j<4;j++){
    r[i*4+j] = a[j]*b[i*4] + a[4+j]*b[i*4+1] + a[8+j]*b[i*4+2] + a[12+j]*b[i*4+3];
  }
  return r;
}

function normalize3(v){
  const l = Math.sqrt(v[0]*v[0]+v[1]*v[1]+v[2]*v[2]);
  return [v[0]/l, v[1]/l, v[2]/l];
}

/* ============================================================
   SHADER SOURCES
   ============================================================ */

const vsSource = `
attribute vec3 aPos;
attribute vec3 aNorm;
attribute vec2 aUV;
uniform mat4 uMVP;
uniform mat4 uModel;
varying vec3 vWorldPos;
varying vec3 vWorldNorm;
varying vec2 vUV;
void main(){
  vec4 worldPos = uModel * vec4(aPos, 1.0);
  vWorldPos = worldPos.xyz;
  vWorldNorm = mat3(uModel) * aNorm;
  vUV = aUV;
  gl_Position = uMVP * vec4(aPos, 1.0);
}`;

const fsSource = `
precision highp float;
varying vec3 vWorldPos;
varying vec3 vWorldNorm;
varying vec2 vUV;
uniform vec3 uLightDir;
uniform vec3 uEyePos;
uniform float uTime;
uniform float uMetalness;
uniform float uRoughness;
uniform sampler2D uTexFront;
uniform sampler2D uTexBack;
uniform sampler2D uTexSide;
uniform int uFaceType; // 0=top, 1=bottom, 2=side

vec3 fresnelSchlick(float cosTheta, vec3 F0){
  return F0 + (1.0 - F0) * pow(clamp(1.0 - cosTheta, 0.0, 1.0), 5.0);
}

float distributionGGX(vec3 N, vec3 H, float roughness){
  float a = roughness * roughness;
  float a2 = a * a;
  float NdotH = max(dot(N, H), 0.0);
  float NdotH2 = NdotH * NdotH;
  float denom = (NdotH2 * (a2 - 1.0) + 1.0);
  denom = 3.14159 * denom * denom;
  return a2 / denom;
}

float geometrySchlickGGX(float NdotV, float roughness){
  float r = roughness + 1.0;
  float k = (r * r) / 8.0;
  return NdotV / (NdotV * (1.0 - k) + k);
}

float geometrySmith(vec3 N, vec3 V, vec3 L, float roughness){
  float NdotV = max(dot(N, V), 0.0);
  float NdotL = max(dot(N, L), 0.0);
  return geometrySchlickGGX(NdotV, roughness) * geometrySchlickGGX(NdotL, roughness);
}

void main(){
  vec3 N = normalize(vWorldNorm);
  vec3 V = normalize(uEyePos - vWorldPos);

  // Determine which texture to use based on face type
  vec3 albedo;
  if(uFaceType == 0){
    albedo = texture2D(uTexFront, vUV).rgb;
  } else if(uFaceType == 1){
    albedo = texture2D(uTexBack, vUV).rgb;
  } else {
    albedo = texture2D(uTexSide, vUV).rgb;
  }

  // Metallic base color
  vec3 F0 = mix(vec3(0.04), albedo, uMetalness);

  // Lighting
  vec3 Lo = vec3(0.0);
  vec3 lightColor = vec3(1.0, 0.95, 0.85);
  vec3 L = normalize(uLightDir);

  // Moving specular highlight
  float highlightPhase = uTime * 3.14159 * 2.0;
  vec3 highlightDir = normalize(vec3(cos(highlightPhase), 0.6, sin(highlightPhase)));
  vec3 H = normalize(L + V);

  float NDF = distributionGGX(N, H, uRoughness);
  float G = geometrySmith(N, V, L, uRoughness);
  vec3 F = fresnelSchlick(max(dot(H, V), 0.0), F0);

  vec3 kS = F;
  vec3 kD = (1.0 - kS) * (1.0 - uMetalness);

  float NdotL = max(dot(N, L), 0.0);
  vec3 diffuse = kD * albedo / 3.14159;

  // Specular with moving highlight boost
  float spec = NDF * G * F / (4.0 * max(dot(N, V), 0.001) + 0.001);

  // Extra specular highlight that moves
  float NdotH = max(dot(N, H), 0.0);
  float extraSpec = pow(NdotH, 64.0) * 1.5;

  // Fresnel rim
  float rim = pow(1.0 - max(dot(N, V), 0.0), 3.0);

  vec3 ambient = vec3(0.02) * albedo;
  vec3 color = (diffuse + spec) * lightColor * NdotL + extraSpec * lightColor + ambient + rim * vec3(0.15, 0.12, 0.08);

  // Tone mapping
  color = color / (color + vec3(1.0));

  // Gamma
  color = pow(color, vec3(1.0 / 2.2));

  gl_FragColor = vec4(color, 1.0);
}`;

