function renderEditionCanvas(canvasEl, edition){
  const size = 180;
  canvasEl.width = size * devicePixelRatio;
  canvasEl.height = size * devicePixelRatio;
  canvasEl.style.width = size + 'px';
  canvasEl.style.height = size + 'px';
  const ctx = canvasEl.getContext('2d');
  const cx = size/2, cy = size/2, r = size/2 - 6;

  let baseColor, highlightColor, shadowColor, ringColor, textColor;

  switch(edition){
    case 'bronze':
      baseColor = ['#c8943e','#a07828','#8a6420'];
      highlightColor = '#f0d078';
      shadowColor = '#6a4a10';
      ringColor = '#b8862d';
      textColor = '#8a6420';
      break;
    case 'silver':
      baseColor = ['#d0d0d8','#a8a8b0','#8888a0'];
      highlightColor = '#f0f0f8';
      shadowColor = '#606070';
      ringColor = '#b0b0c0';
      textColor = '#505060';
      break;
    case 'gold':
      baseColor = ['#f0d078','#d4a843','#b8862d'];
      highlightColor = '#fff8e0';
      shadowColor = '#8a6420';
      ringColor = '#c8943e';
      textColor = '#8a6420';
      break;
    case 'black':
      baseColor = ['#2a2a3e','#1a1a2e','#0a0a18'];
      highlightColor = '#4a4a6e';
      shadowColor = '#000008';
      ringColor = '#3a3a5e';
      textColor = '#5a5a7e';
      break;
  }

  // Background
  const grad = ctx.createRadialGradient(cx - r*0.3, cy - r*0.3, r*0.05, cx, cy, r);
  grad.addColorStop(0, highlightColor);
  grad.addColorStop(0.4, baseColor[0]);
  grad.addColorStop(1, baseColor[2]);
  ctx.fillStyle = grad;
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI*2);
  ctx.fill();

  // Reeded edge effect
  ctx.strokeStyle = shadowColor;
  ctx.lineWidth = 1;
  for(let i=0;i<60;i++){
    const a = (i/60)*Math.PI*2;
    const x1 = cx + Math.cos(a)*(r-2);
    const y1 = cy + Math.sin(a)*(r-2);
    const x2 = cx + Math.cos(a)*r;
    const y2 = cy + Math.sin(a)*r;
    ctx.beginPath();
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();
  }

  // Inner ring
  ctx.strokeStyle = ringColor;
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.arc(cx, cy, r*0.85, 0, Math.PI*2);
  ctx.stroke();

  // Star emblem
  const starR = r * 0.35;
  ctx.fillStyle = highlightColor;
  ctx.shadowColor = 'rgba(0,0,0,0.4)';
  ctx.shadowBlur = 3;
  ctx.shadowOffsetX = 1;
  ctx.shadowOffsetY = 1;
  drawStar(ctx, cx, cy, 5, starR, starR*0.45);
  ctx.shadowBlur = 0;

  // Text
  ctx.font = `bold ${size*0.055}px 'Segoe UI', sans-serif`;
  ctx.fillStyle = textColor;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.shadowColor = 'rgba(255,255,255,0.2)';
  ctx.shadowBlur = 1;
  ctx.shadowOffsetX = 1;
  ctx.shadowOffsetY = 1;

  const labels = {bronze:'WASTEDTOKEN',silver:'WASTEDTOKEN',gold:'WASTEDTOKEN',black:'WASTEDTOKEN'};
  ctx.fillText(labels[edition], cx, cy - r*0.45);
  ctx.font = `bold ${size*0.045}px 'Segoe UI', sans-serif`;
  ctx.fillText('MINT', cx, cy + r*0.45);

  // Overlay for sold-out / coming-soon
  if(edition === 'gold'){
    ctx.fillStyle = 'rgba(0,0,0,0.25)';
    ctx.beginPath();
    ctx.arc(cx, cy, r, 0, Math.PI*2);
    ctx.fill();
  }
  if(edition === 'black'){
    ctx.fillStyle = 'rgba(0,0,0,0.35)';
    ctx.beginPath();
    ctx.arc(cx, cy, r, 0, Math.PI*2);
    ctx.fill();
  }
}

